    if (n < 4) return 0;

    let count = 0;
    const lines = new Map();

    for (let i = 0; i < n; i++) {
        for (let j = i + 1; j < n; j++) {
            const x1 = points[i][0], y1 = points[i][1];
            const x2 = points[j][0], y2 = points[j][1];
            let key;
            if (x1 === x2) {
                key = `inf_${x1}`;
            } else {
                const slope = (y2 - y1) / (x2 - x1);
                const intercept = y1 - slope * x1;
                key = `${slope}_${intercept}`;
            }
            if (!lines.has(key)) {
                lines.set(key, []);
            }
            lines.get(key).push([i, j]);
        }
    }

    for (const [key, pairs] of lines) {
        const m = pairs.length;
        if (m < 2) continue;
        const usedPoints = new Set();
        for (const [i, j] of pairs) {
            usedPoints.add(i);
            usedPoints.add(j);
        }
        const totalPoints = usedPoints.size;
        count += totalPoints >= 4 ? combinations(totalPoints, 4) * combinations(m, 2) / combinations(totalPoints - 2, 2) : 0;
    }

    return count;
}

